import React from 'react';
import { Smartphone, Lock, Network } from 'lucide-react';

const HowItWorks = () => {
  const steps = [
    {
      icon: Smartphone,
      title: "Development",
      description: "We jump on a call. We build your digital engine using the latest tech stack."
    },
    {
      icon: Lock,
      title: "Mobile-First",
      description: "SSL, encryption, and data protection as standard."
    },
    {
      icon: Network,
      title: "AI-Integrated",
      description: "Options for chatbots or automated workflows."
    }
  ];

  return (
    <section className="py-20 px-4 sm:px-6 lg:px-8">
      <div className="max-w-7xl mx-auto">
        <h2 className="text-3xl sm:text-4xl font-black text-white text-center mb-16">
          HOW IT WORKS
        </h2>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          {/* Left Side - Numbered Circles */}
          <div className="flex justify-center lg:justify-start">
            <div className="relative">
              {/* Vertical Line */}
              <div className="absolute left-6 top-8 bottom-8 w-0.5 bg-apex-blue"></div>

              {/* Numbered Circles */}
              {[1, 2, 3].map((number) => (
                <div key={number} className="flex items-center mb-8 last:mb-0">
                  <div className="relative z-10 w-12 h-12 bg-apex-blue rounded-full flex items-center justify-center text-white font-bold text-lg">
                    {number}
                  </div>
                  <div className="ml-6">
                    <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center">
                      {number === 1 && <Smartphone className="w-8 h-8 text-apex-blue" />}
                      {number === 2 && <Lock className="w-8 h-8 text-apex-blue" />}
                      {number === 3 && <Network className="w-8 h-8 text-apex-blue" />}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Right Side - Cards */}
          <div className="space-y-6">
            {steps.map((step, index) => {
              const Icon = step.icon;
              return (
                <div 
                  key={index}
                  className="bg-gray-900 border border-gray-800 rounded-lg p-6 hover:border-apex-blue transition-all duration-300"
                >
                  <div className="flex items-start space-x-4">
                    <div className="w-12 h-12 bg-apex-blue rounded-full flex items-center justify-center flex-shrink-0">
                      <Icon className="w-6 h-6 text-white" />
                    </div>

                    <div>
                      <h3 className="text-xl font-bold text-white mb-2">
                        {step.title}
                      </h3>
                      <p className="text-gray-300 leading-relaxed">
                        {step.description}
                      </p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </section>
  );
};

export default HowItWorks;
